import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { 
  FaMicrophone, 
  FaMicrophoneSlash, 
  FaPhoneSlash, 
  FaVolumeUp, 
  FaVolumeMute,
  FaUserMd,
  FaPhone,
  FaPhoneAlt
} from 'react-icons/fa';

import './VideoCallPage.css';

const AudioCallPage = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();
  const doctor = location.state?.doctor;

  // Call states
  const [callDuration, setCallDuration] = useState(0);
  const [callStatus, setCallStatus] = useState('ringing'); // 'ringing', 'connected', 'ended'
  const [isMuted, setIsMuted] = useState(false);
  const [isSpeakerOn, setIsSpeakerOn] = useState(false);
  const [isCallActive, setIsCallActive] = useState(true);
  // fullscreen state is managed via DOM fullscreen API; no local flag needed

  useEffect(() => {
    // Redirect if no doctor data
    if (!doctor) {
      navigate('/');
      return;
    }

    // Simulate call connection after 3 seconds of ringing
    const connectionTimer = setTimeout(() => {
      if (callStatus === 'ringing') {
        setCallStatus('connected');
      }
    }, 3000);

    return () => clearTimeout(connectionTimer);
  }, [doctor, navigate, callStatus]);

  useEffect(() => {
    // Start call timer when connected
    let timer;
    if (callStatus === 'connected' && isCallActive) {
      timer = setInterval(() => {
        setCallDuration(prev => prev + 1);
      }, 1000);
    }

    return () => {
      if (timer) clearInterval(timer);
    };
  }, [callStatus, isCallActive]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleEndCall = () => {
    setCallStatus('ended');
    setIsCallActive(false);
    
    // Show call ended for 2 seconds then navigate back
    setTimeout(() => {
      navigate('/');
    }, 2000);
  };

  const toggleFullscreen = () => {
    const stage = document.querySelector('.vc-audio-stage');
    if (!stage) return;
    if (!document.fullscreenElement) {
      if (stage.requestFullscreen) stage.requestFullscreen();
      else if (stage.webkitRequestFullscreen) stage.webkitRequestFullscreen();
    } else {
      if (document.exitFullscreen) document.exitFullscreen();
      else if (document.webkitExitFullscreen) document.webkitExitFullscreen();
    }
  };

  const getStatusText = () => {
    switch (callStatus) {
      case 'ringing':
        return 'Ringing...';
      case 'connected':
        return formatTime(callDuration);
      case 'ended':
        return 'Call Ended';
      default:
        return 'Connecting...';
    }
  };

  const getStatusColor = () => {
    switch (callStatus) {
      case 'ringing':
        return 'text-blue-400';
      case 'connected':
        return 'text-green-400';
      case 'ended':
        return 'text-red-400';
      default:
        return 'text-gray-400';
    }
  };

  if (!doctor) {
    return null;
  }

  return (
    <div className="fixed inset-0 bg-gradient-to-br from-gray-900 via-blue-900 to-gray-900 flex flex-col">
      {/* Status Bar Area */}
      <div className="h-8 bg-transparent"></div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col items-center justify-center px-6 text-white relative">
        
        {/* Call Status Indicator */}
        <div className="absolute top-8 left-0 right-0 text-center">
          <div className="inline-flex items-center space-x-2 bg-black/30 backdrop-blur-sm px-4 py-2 rounded-full">
            {callStatus === 'ringing' && (
              <div className="w-2 h-2 bg-blue-400 rounded-full animate-pulse"></div>
            )}
            {callStatus === 'connected' && (
              <div className="w-2 h-2 bg-green-400 rounded-full"></div>
            )}
            {callStatus === 'ended' && (
              <div className="w-2 h-2 bg-red-400 rounded-full"></div>
            )}
            <span className="text-sm text-gray-200 font-medium">
              {callStatus === 'ringing' && 'Calling'}
              {callStatus === 'connected' && 'Connected'}
              {callStatus === 'ended' && 'Disconnected'}
            </span>
          </div>
        </div>

        {/* Doctor card - unified and centered */}
        <div className="vc-audio-stage">
          <div className="vc-audio-card">
            <div className="vc-audio-avatar">{doctor.name?.charAt(0)}</div>
            <div className="vc-audio-details">
              <div className="vc-audio-title">
                <h2 className="vc-name">{doctor.name}</h2>
                <div className="vc-timer">{getStatusText()}</div>
              </div>
              <div className="vc-meta">{doctor.specialty}</div>
              <div className="vc-small">{doctor.qualifications}</div>
              <div className="vc-audio-row">
                <div className="vc-status-row"><span className="dot available"></span> <span className="vc-available-text">Available</span></div>
                <div className="vc-exp">{doctor.experience} years exp</div>
                <div className="vc-langs">{doctor.languages}</div>
              </div>
            </div>
          </div>
        </div>

        {/* Controls bar (fixed, always visible) */}
        <div className="vc-controls" role="toolbar" aria-label="call controls">
          <button
            onClick={() => setIsMuted(!isMuted)}
            disabled={callStatus !== 'connected'}
            className={`control-btn ${isMuted ? 'muted active' : ''}`}
            title={isMuted ? 'Unmute' : 'Mute'}
          >
            {isMuted ? <FaMicrophoneSlash /> : <FaMicrophone />}
          </button>

          <button
            onClick={handleEndCall}
            disabled={callStatus === 'ended'}
            className={`control-btn end`}
            title="End Call"
          >
            <FaPhoneSlash />
          </button>

          <button
            onClick={() => setIsSpeakerOn(!isSpeakerOn)}
            disabled={callStatus !== 'connected'}
            className={`control-btn ${isSpeakerOn ? 'active' : ''}`}
            title={isSpeakerOn ? 'Speaker Off' : 'Speaker On'}
          >
            {isSpeakerOn ? <FaVolumeUp /> : <FaVolumeMute />}
          </button>

          <button className="control-btn" title="Fullscreen" onClick={toggleFullscreen}>
            <FaPhone />
          </button>
        </div>

        {/* Visual Call Waves (when connected) */}
        {callStatus === 'connected' && !isMuted && (
          <div className="flex items-center justify-center space-x-1 mb-8">
            {[...Array(5)].map((_, i) => (
              <div
                key={i}
                className="w-1 bg-green-400 rounded-full animate-pulse"
                style={{
                  height: `${Math.random() * 20 + 10}px`,
                  animationDelay: `${i * 0.1}s`,
                  animationDuration: '0.5s'
                }}
              ></div>
            ))}
          </div>
        )}
      </div>

        {/* Doctor details panel removed - now using centered card `.vc-audio-card` above for a single professional layout during call */}

      {/* Emergency Info (when call ends) */}
      {callStatus === 'ended' && (
        <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
          <div className="bg-white rounded-lg p-6 mx-6 text-center shadow-2xl">
            <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <FaPhoneSlash className="text-red-600 text-2xl" />
            </div>
            <h3 className="text-lg font-semibold text-gray-900 mb-2">Call Ended</h3>
            <p className="text-gray-600 text-sm">
              Call duration: {formatTime(callDuration)}
            </p>
            <p className="text-gray-500 text-xs mt-2">
              Returning to home page...
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default AudioCallPage;
